// Script: generar_19_multimascota_prevencion_analisis_perfil.js
// Que hace: cierra la funcion multi-mascota, agregando el selector
// completo y funcional a las ultimas 3 pantallas, mas el boton de
// "agregar otra mascota" en Perfil.
//
//   1) app/prevencion/page.tsx -- selector debajo del header, reutiliza
//      la funcion cargarDatos() existente al cambiar de mascota. Toda la
//      logica de las 7 pestanas (incluyendo Examenes con PDFs) se
//      mantiene intacta.
//
//   2) app/analisis/page.tsx -- selector debajo del header. Se extrajo
//      la carga de registros a una funcion reutilizable (cargarRegistros)
//      para no duplicar codigo entre la carga inicial y el cambio de
//      mascota.
//
//   3) app/perfil/page.tsx -- selector despues del header con degradado
//      (para no competir visualmente con el avatar/nombre de la mascota
//      activa). Al cambiar de mascota, el modo edicion se cierra
//      automaticamente para evitar editar los datos de una mascota
//      pensando que es otra. Se agrego ademas el boton "+ Agregar otra
//      mascota" dentro de la tarjeta "Mi cuenta", junto a "Cerrar sesion".
//
// Con esto, las 6 pantallas internas (dashboard, calendario, registro
// diario, prevencion, analisis, perfil) ya soportan multiples mascotas
// por usuario, con un selector consistente en todas.
//
// Como correrlo: node generar_19_multimascota_prevencion_analisis_perfil.js
// Confirma "OK" para los 3 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/prevencion/page.tsx', "");
escribir('app/analisis/page.tsx', "");
escribir('app/perfil/page.tsx', "");
